      const aspects = (d?.tropical?.aspects || [])
        .slice(0, 6)
        .map((a: any) => `${a.p1}-${a.p2} ${a.type}`)
        .join(', ')
      const ascDelta =
        d?.fusionMeta?.ascDelta != null
